import { redirect } from "next/navigation";
import { getCurrentUser } from "@/lib/session";
import { getTeamMembers } from "@/lib/team";
import { GiveKudosForm } from "@/components/kudos/GiveKudosForm";

export default async function GiveKudosPage() {
  const currentUser = await getCurrentUser();
  if (!currentUser) {
    redirect("/?from=give-kudos");
  }

  const teamMembers = await getTeamMembers();
  if (teamMembers.length === 0) {
    return (
      <div className="max-w-3xl mx-auto px-4 py-8">
        <h1 className="text-2xl font-semibold text-[#212631]">Give Kudos</h1>
        <p className="mt-2 text-[#3d4657]">No team members found. Run the database seed first.</p>
      </div>
    );
  }

  return (
    <div className="min-h-full bg-[#f5f6f8]">
      <div className="max-w-3xl mx-auto px-4 py-8">
        <h1 className="text-2xl font-semibold text-[#212631]">Give Kudos</h1>
        <p className="mt-1 text-sm text-[#66686c]">
          Choose who you’re recognizing, pick a category, and write a short message.
        </p>
        <div className="mt-6">
          <GiveKudosForm teamMembers={teamMembers} />
        </div>
      </div>
    </div>
  );
}
